'use client'

import React, { useState } from 'react';
import { useBudget } from '@/context/BudgetContext';
import { User, Lock, ArrowRight, Loader2, CheckCircle2, AlertCircle, Eye, EyeOff } from 'lucide-react';
import { GoogleLogin } from '@react-oauth/google';
import { useRouter } from 'next/navigation';

export default function Login() {
    const { login, loginWithGoogle } = useBudget();
    const router = useRouter();
    const [username, setUsername] = useState('');
    const [password, setPassword] = useState('');
    const [showPass, setShowPass] = useState(false);
    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState('');

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsLoading(true);
        setError('');
        try {
            const success = await login(username, password);
            if (success) {
                router.push('/dashboard');
            } else {
                setError('ชื่อผู้ใช้งานหรือรหัสผ่านไม่ถูกต้อง');
            }
        } catch (err: any) {
            setError(`เกิดข้อผิดพลาด: ${err.message || 'กรุณาลองใหม่อีกครั้ง'}`);
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="min-h-screen w-full flex">

            {/* ── LEFT: Branding Panel ── */}
            <div className="hidden lg:flex lg:w-[50%] flex-col justify-between relative overflow-hidden"
                style={{ background: 'linear-gradient(160deg, #0D3B66 0%, #1A5276 30%, #2471A3 65%, #2E86C1 100%)' }}>

                {/* Subtle texture */}
                <div className="absolute inset-0 opacity-[0.04]"
                    style={{ backgroundImage: 'radial-gradient(circle, white 1px, transparent 1px)', backgroundSize: '32px 32px' }} />

                <div className="relative z-10 flex flex-col justify-between h-full px-12 py-10">
                    {/* Top badge */}
                    <div>
                        <span className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full bg-white/10 border border-white/15 text-[11px] font-semibold text-white/80 tracking-wide">
                            <span className="w-1.5 h-1.5 rounded-full bg-emerald-400" />
                            ระบบบริหารจัดการงบประมาณองค์กร
                        </span>
                    </div>

                    {/* Center content */}
                    <div className="space-y-6 max-w-md">
                        <h1 className="text-[40px] font-bold text-white leading-tight tracking-tight">
                            Smart Budget<br />
                            <span className="text-primary-200">Management</span>
                        </h1>
                        <p className="text-[15px] text-white/60 leading-relaxed">
                            ยกระดับการบริหารงบประมาณด้วยความโปร่งใส รวดเร็ว และ
                            แม่นยำ ด้วยระบบ Digital Trust Platform ที่ทันสมัยที่สุด
                        </p>

                        {/* Feature pills */}
                        <div className="flex gap-3 pt-2">
                            <div className="flex items-center gap-3 px-5 py-3 rounded-xl bg-white/10 border border-white/10">
                                <span className="text-xl">🔒</span>
                                <div>
                                    <p className="text-sm font-bold text-white">100%</p>
                                    <p className="text-[11px] text-white/50">Data Security</p>
                                </div>
                            </div>
                            <div className="flex items-center gap-3 px-5 py-3 rounded-xl bg-white/10 border border-white/10">
                                <span className="text-xl">⚡</span>
                                <div>
                                    <p className="text-sm font-bold text-white">Real-time</p>
                                    <p className="text-[11px] text-white/50">Budget Tracking</p>
                                </div>
                            </div>
                        </div>
                    </div>

                    {/* Bottom */}
                    <p className="text-[10px] text-white/20 tracking-[0.15em] uppercase">
                        Secured by DCC Platform • v3.0
                    </p>
                </div>
            </div>

            {/* ── RIGHT: Login Form ── */}
            <div className="flex-1 flex flex-col items-center justify-center px-6 py-10 bg-white">
                <div className="w-full max-w-[420px]">

                    {/* Mobile logo */}
                    <div className="lg:hidden mb-6">
                        <div className="w-10 h-10 rounded-xl bg-primary-600 text-white flex items-center justify-center">
                            <CheckCircle2 className="w-5 h-5" />
                        </div>
                    </div>

                    {/* Form header */}
                    <div className="mb-8">
                        <div className="w-10 h-10 rounded-full bg-primary-50 flex items-center justify-center mb-4">
                            <CheckCircle2 className="w-5 h-5 text-primary-600" />
                        </div>
                        <h2 className="text-2xl font-bold text-gray-900">ยินดีต้อนรับกลับมา!</h2>
                        <p className="text-sm text-gray-500 mt-1">เข้าสู่ระบบเพื่อดำเนินการบริหารงบประมาณ</p>
                    </div>

                    {/* Error */}
                    {error && (
                        <div className="mb-5 flex items-center gap-2.5 px-4 py-3 bg-red-50 border border-red-200 rounded-xl text-sm">
                            <AlertCircle className="w-4 h-4 text-red-500 flex-shrink-0" />
                            <span className="text-red-600 font-medium">{error}</span>
                        </div>
                    )}

                    {/* Form */}
                    <form onSubmit={handleSubmit} className="space-y-5">
                        {/* Username */}
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1.5">ชื่อผู้ใช้งาน</label>
                            <div className="relative">
                                <div className="absolute inset-y-0 left-0 pl-3.5 flex items-center pointer-events-none">
                                    <User className="w-4 h-4 text-gray-400" />
                                </div>
                                <input
                                    type="text" required value={username}
                                    onChange={(e) => setUsername(e.target.value)}
                                    className="w-full pl-10 pr-4 py-2.5 rounded-xl border border-gray-200 bg-white text-sm text-gray-900 font-medium
                                        placeholder:text-gray-400 placeholder:font-normal
                                        focus:outline-none focus:border-primary-400 focus:ring-2 focus:ring-primary-100
                                        transition-colors disabled:opacity-50"
                                    placeholder="ระบุชื่อผู้ใช้งาน"
                                    disabled={isLoading}
                                    autoComplete="username"
                                />
                            </div>
                        </div>

                        {/* Password */}
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1.5">รหัสผ่าน</label>
                            <div className="relative">
                                <div className="absolute inset-y-0 left-0 pl-3.5 flex items-center pointer-events-none">
                                    <Lock className="w-4 h-4 text-gray-400" />
                                </div>
                                <input
                                    type={showPass ? 'text' : 'password'} required value={password}
                                    onChange={(e) => setPassword(e.target.value)}
                                    className="w-full pl-10 pr-10 py-2.5 rounded-xl border border-gray-200 bg-white text-sm text-gray-900 font-medium
                                        placeholder:text-gray-400 placeholder:font-normal
                                        focus:outline-none focus:border-primary-400 focus:ring-2 focus:ring-primary-100
                                        transition-colors disabled:opacity-50"
                                    placeholder="••••••••"
                                    disabled={isLoading}
                                    autoComplete="current-password"
                                />
                                <button type="button" onClick={() => setShowPass(!showPass)}
                                    className="absolute inset-y-0 right-0 pr-3.5 flex items-center text-gray-400 hover:text-gray-600">
                                    {showPass ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                                </button>
                            </div>
                        </div>

                        {/* Divider */}
                        <div className="flex items-center gap-3 py-1">
                            <div className="flex-1 h-px bg-gray-100" />
                            <span className="text-[10px] font-medium text-gray-400 uppercase tracking-wider">or continue with</span>
                            <div className="flex-1 h-px bg-gray-100" />
                        </div>

                        {/* Google Login */}
                        <div className="flex justify-center">
                            <GoogleLogin
                                onSuccess={async (credentialResponse) => {
                                    if (credentialResponse.credential) {
                                        setIsLoading(true);
                                        try {
                                            const success = await loginWithGoogle(credentialResponse.credential);
                                            if (success) router.push('/dashboard');
                                        } catch { setError('Google Sign-In Error'); }
                                        finally { setIsLoading(false); }
                                    }
                                }}
                                onError={() => setError('Google Sign-In Failed')}
                                shape="pill" theme="outline" size="large"
                                text="signin_with"
                            />
                        </div>

                        {/* Submit Button */}
                        <button type="submit" disabled={isLoading}
                            className="w-full flex items-center justify-center gap-2 py-3 px-6 rounded-xl
                                bg-primary-600 hover:bg-primary-700 text-white text-sm font-semibold
                                shadow-sm hover:shadow-md transition-all
                                disabled:opacity-50 disabled:cursor-not-allowed">
                            {isLoading ? (
                                <Loader2 className="w-4 h-4 animate-spin" />
                            ) : (
                                <>เข้าสู่ระบบ <ArrowRight className="w-4 h-4" /></>
                            )}
                        </button>
                    </form>

                    {/* Footer links */}
                    <div className="mt-6 text-center space-y-2">
                        <p className="text-sm text-gray-500">
                            ไม่มีบัญชีผู้ใช้งาน? <span className="text-primary-600 font-semibold cursor-pointer hover:underline">ติดต่อผู้ดูแลระบบ</span>
                        </p>
                        <p className="text-sm text-primary-600 font-medium cursor-pointer hover:underline">
                            ลืมรหัสผ่าน?
                        </p>
                    </div>
                </div>
            </div>
        </div>
    );
}
